+function writeHexLen(buf: Uint8Array, len: number): void {
+  buf[0] = len >> 12 & 0xf;
+  buf[1] = len >> 8 & 0xf;
+  buf[2] = len >> 4 & 0xf;
+  buf[3] = len & 0xf;
+  for (let i = 0; i < 4; i++) {
+    buf[i] = buf[i] < 10 ? buf[i] + 0x30 : buf[i] - 10 + 0x61;
+  }
+}
